mapper.select:
select max(decode(typeName, 'used', oneCount, 0)) as usedCount,
       max(decode(typeName, 'disableUsed', oneCount, 0)) as disableUsedCount
  from (select 'used' as typeName, count(*) as oneCount
          from STANDARDIZE_INPUTOBJECTRELATE
         where IOBJ_GUID = #{inputGuid}
           and OOBJ_GUID = #{outputGuid}
           and IOR_SOURCE = #{inputIobjSource}
           and IOR_STATUS = 1
        union ALL
        select 'disableUsed' as typeName, count(*) as oneCount
          from STANDARDIZE_INPUTOBJECTRELATE
         where IOBJ_GUID = #{inputGuid}
           and OOBJ_GUID = #{outputGuid}
           and IOR_SOURCE = #{inputIobjSource}
           and IOR_STATUS = 0)
